import * as React from 'react';
import { render, screen, waitFor, act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { DatePicker } from './DatePicker';

jest.mock('rsuite', () => {
  return {
    DateRangePicker: React.forwardRef<
      HTMLDivElement,
      { onChange?: (value: [unknown, unknown]) => void; showOneCalendar?: boolean; open?: boolean }
    >((props, ref) => {
      const { onChange, showOneCalendar, open } = props;

      return (
        <div
          ref={ref}
          role="button"
          tabIndex={0}
          data-testid="date-range-picker"
          data-prop-show-one={showOneCalendar ? 'true' : 'false'}
          data-prop-open={open ? 'true' : 'false'}
          onClick={() => {
            const payload: [unknown, unknown] = [new Date(0), new Date(0)];
            onChange?.(payload);
          }}
        >
          DateRangePicker
        </div>
      );
    })
  };
});

const setupMatchMedia = (initialMatches: boolean) => {
  let matches = initialMatches;
  const listeners = new Set<(event: { matches: boolean }) => void>();

  const mediaQueryList = {
    get matches() {
      return matches;
    },
    media: '(min-width: 1024px)',
    addEventListener: (_event: string, callback: (event: { matches: boolean }) => void) => {
      listeners.add(callback);
    },
    removeEventListener: (_event: string, callback: (event: { matches: boolean }) => void) => {
      listeners.delete(callback);
    }
  } as unknown as MediaQueryList;

  Object.defineProperty(window, 'matchMedia', {
    writable: true,
    value: jest.fn().mockImplementation(() => mediaQueryList)
  });

  const dispatch = (next: boolean) => {
    matches = next;
    listeners.forEach(callback => callback({ matches: next }));
  };

  return { dispatch };
};

describe('DatePicker', () => {
  it('renders wrapper with base token classes', () => {
    setupMatchMedia(false);
    render(<DatePicker />);
    const container = screen.getByTestId('date-range-picker').parentElement;
    expect(container?.className).toContain('bg-modal-dark');
  });

  it('applies fullWidth layout class when enabled', () => {
    setupMatchMedia(false);
    render(<DatePicker fullWidth />);
    const container = screen.getByTestId('date-range-picker').parentElement;
    expect(container?.className).toContain('w-full');
  });

  it('defaults to showOneCalendar=true below lg breakpoint', async () => {
    setupMatchMedia(false);
    render(<DatePicker />);
    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    await waitFor(() => {
      expect(container).toHaveAttribute('data-show-one-calendar', 'true');
    });
  });

  it('defaults to showOneCalendar=false at or above lg breakpoint', async () => {
    setupMatchMedia(true);
    render(<DatePicker />);
    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    await waitFor(() => {
      expect(container).not.toHaveAttribute('data-show-one-calendar');
    });
  });

  it('honors explicit showOneCalendar=true', async () => {
    setupMatchMedia(true);
    render(<DatePicker showOneCalendar />);
    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    await waitFor(() => {
      expect(container).toHaveAttribute('data-show-one-calendar', 'true');
    });
  });

  it('honors explicit showOneCalendar=false', async () => {
    setupMatchMedia(false);
    render(<DatePicker showOneCalendar={false} />);
    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    await waitFor(() => {
      expect(container).not.toHaveAttribute('data-show-one-calendar');
    });
  });

  it('forwards onChange to rsuite DateRangePicker', async () => {
    setupMatchMedia(false);
    const handleChange = jest.fn();
    const user = userEvent.setup();
    render(<DatePicker onChange={handleChange} />);
    await user.click(screen.getByRole('button', { name: 'DateRangePicker' }));
    expect(handleChange).toHaveBeenCalledTimes(1);
  });

  it('merges custom className on the wrapper', () => {
    setupMatchMedia(false);
    render(<DatePicker className="u-test" />);
    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    expect(container.className).toContain('u-test');
  });

  it('passes effective showOneCalendar to rsuite (responsive default)', async () => {
    setupMatchMedia(false);
    render(<DatePicker />);
    const inner = screen.getByTestId('date-range-picker');
    await waitFor(() => {
      expect(inner).toHaveAttribute('data-prop-show-one', 'true');
    });
  });

  it('passes explicit showOneCalendar=false to rsuite', async () => {
    setupMatchMedia(false);
    render(<DatePicker showOneCalendar={false} />);
    const inner = screen.getByTestId('date-range-picker');
    await waitFor(() => {
      expect(inner).toHaveAttribute('data-prop-show-one', 'false');
    });
  });

  it('opens the RSuite picker when clicking the visible Input', async () => {
    setupMatchMedia(false);
    render(<DatePicker />);

    const input = screen.getByTestId('date-picker-input');
    await userEvent.click(input);

    const inner = screen.getByTestId('date-range-picker');
    await waitFor(() => {
      expect(inner).toHaveAttribute('data-prop-open', 'true');
    });
  });

  it('defaults safely when window.matchMedia is unavailable (no-support path)', async () => {
    const originalMatchMedia = window.matchMedia;

    (window as unknown as { matchMedia: typeof window.matchMedia | null }).matchMedia = null;

    try {
      render(<DatePicker />);

      const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
      await waitFor(() => {
        expect(container).toHaveAttribute('data-show-one-calendar', 'true');
      });
    } finally {
      (window as unknown as { matchMedia: typeof window.matchMedia }).matchMedia = originalMatchMedia;
    }
  });

  it('responds to breakpoint change events (toggles one/two calendar after mount)', async () => {
    const { dispatch } = setupMatchMedia(false);
    render(<DatePicker />);

    act(() => {
      dispatch(true);
    });

    const container = screen.getByTestId('date-range-picker').parentElement as HTMLElement;
    await waitFor(() => {
      expect(container).not.toHaveAttribute('data-show-one-calendar');
    });
  });
});
